int ZString::compare(std::string&amp; num1, std::string&amp; num2) &#123;
	size_t len_1 &#x3D; num1.size(), len_2 &#x3D; num2.size();
	if (len_1 &gt; len_2)		return 1;
	else if (len_1 &lt; len_2)	return -1;
