顺序查找法从序列的一端开始遍历到另一端，找到对应元素则返回对应下标（或做其他处理），找不到则返回-1.
&#x3D;&#x3D;可能查找得到，也可能查找不到&#x3D;&#x3D;。
时间复杂度是O(n)
ASL &#x3D; (1+2+3+…+n)&#x2F;n&#x3D;(1+n)*n&#x2F;2&#x2F;n&#x3D;(1+n)&#x2F;2
int querySearch(int arr[],int length,int key) &#123;
    for (int i &#x3D; 0;i &lt; length; i++) &#123;
        if (key &#x3D;&#x3D; arr[i]) return i;
    &#125;
    return -1;
&#125;



哨兵法查找选取头部（尾部）位置做哨兵，从尾部（头部）开始遍历到头部（尾部），找到对应元素则返回对应下标。
原来的内存中有一个单元是不用的，这个单元用来存储哨兵。
&#x3D;&#x3D;一定会查找得到&#x3D;&#x3D;。
&#x3D;&#x3D;和顺序查找是一个意思&#x3D;&#x3D;。
&#x2F;&#x2F;0号位置不放原始数据，用于存储哨兵（待查找的数据）
int querySearch(int arr[],int length,int key) &#123;
    arr[0] &#x3D; key;
    while(arr[0] !&#x3D; arr[--length]);
    return length;
&#125;

时间复杂度是O(n)
二分查找法前提：&#x3D;&#x3D;序列有序，并且是顺序存储&#x3D;&#x3D;。因为链表不能跳着访问。
每一次都是拿要查找的数和子序列的中间位置比较，如果要查找的数比中间位置的小就往左边继续找，如果要查找的数比中间位置的大就往 右边继续找，如果要查找的数和中间位置的数一样大就结束递归返回中间位置的下标，经历了多次这样的寻找后仍然找不到就说明序列中没有这个数直接返回-1.
循环写法：
int binarySearch(int arr[],int left,int right,int key) &#123;
    int mid;
    while (left &lt;&#x3D; right) &#123;
        mid &#x3D; left + (right - left)&#x2F;2;
        if (key &lt; arr[mid]) right &#x3D; mid - 1;
        else if(key &gt; arr[mid]) left &#x3D; mid + 1;
        else return mid;
    &#125;
    return -1;
&#125;

递归写法：
int binarySearch(int arr[],int left,int right,int key) &#123;
    if (left &gt; right) return -1;
    int mid &#x3D; left + (right - left)&#x2F;2;
	if (key &lt; arr[mid]) binarySearch(arr,left,mid - 1,key);
    else if(key &gt; arr[mid]) binarySearch(arr,mid + 1,right,key);
    else return mid;
&#125;

时间复杂度是O(logn)
1   n&#x2F;2
2   n&#x2F;2&#x2F;2
3   n&#x2F;2&#x2F;2&#x2F;2
…
x &#x3D; logn
分块查找法需要一个符号表，存储序列中几个比较特殊的元素，在查找之前先在符号表找一遍，然后再到对应的区域进行查找操作。同样的也是找到就返回对应的下标，否则返回-1.
符号表的结构体描述：
typedef struct Data &#123;
	int key;
	int index;
&#125;Data, ST;

int blocksearch(int arr[], int length, ST* st, int len_st, int key) &#123;
	int left &#x3D; 0, right &#x3D; len_st - 1;
	int mid &#x3D; left + ((right - left) &gt;&gt; 1);
	&#x2F;&#x2F;二分法查找区间
    while (left &lt; right) &#123;
		if (key &lt; st[mid].key)  	  right &#x3D; mid; &#x2F;&#x2F;因为最大值包含在其中，所有不能漏掉right所对应的值
		else if (key &gt; st[mid].key)	  left &#x3D; mid + 1; &#x2F;&#x2F;因为left所有对应的比过了，就直接跳开
		else break;
		mid &#x3D; left + ((right - left) &gt;&gt; 1);
	&#125;
	int begin &#x3D; st[mid].index;
	int end &#x3D; mid &gt;&#x3D; len_st - 1 ? length : st[mid + 1].index;
	&#x2F;&#x2F;在对应的区间中顺序查找
    while (begin &lt; end) &#123;
		if (key &#x3D;&#x3D; arr[begin]) return begin;
		begin++;
	&#125;
	return -1;
&#125;

void printElement(int arr[], int length, int index) &#123;
	if (index &lt; 0 || index &gt;&#x3D; length)
		printf(&quot;下标越界\n&quot;);
	else
		printf(&quot;index &#x3D; %d\tvalue &#x3D; %d\n&quot;, index, arr[index]);
&#125;

int main() &#123;
	srand((unsigned int)time(NULL));
	int arr[15] &#x3D; &#123; 5,7,9,1,3 ,24,26,28,22,21,47,57,42,56,37 &#125;;
	showArr(arr, 15);
	ST st[3] &#x3D; &#123;
		&#123;9,0&#125;,
		&#123;28,5&#125;,
		&#123;57,10&#125;
	&#125;;
	int index &#x3D; blocksearch(arr, 15, st, 3, 50);
	printElement(arr, sizeof(arr) &#x2F; sizeof(arr[0]), index);
	return 0;
&#125;


O(logk+m)
二叉查找树查找法解决&#x3D;&#x3D;链式存储结构&#x3D;&#x3D;的查找。封装一个有序二叉树，该树的特征是中序遍历是有序的（所以又叫二叉排序树），并且每一颗子树中的父亲都比左子树大并且比右子树小。查找的时候就从根部开始向下查找，如果小于则往左边找，大于则往右边找，等于就直接返回，如果都遍历到底部了仍然没有找到就返回NULL.
类似二分查找。
适合动态增加和删除的查找算法。
时间复杂度：

一般是O(logn)
最坏情况：O(n)

当二叉查找形成一边倒的时候就会出现最坏情况，这个时候的查找变成是链表的顺序查找（没有发挥出二叉树的优势）了，就慢了很多。
二叉查找树的结构体描述：
typedef struct BSTree
&#123;
	int key;
	struct BSTree* lchild;
	struct BSTree* rchild;
&#125;BSTree,Node;

二叉查找树的几个相关函数
Node* createNode(int data);
BSTree* insertNode(BSTree* tree, int data);
Node* deleteNode(BSTree* tree, int key);
Node* searchNode(BSTree* tree, int key);
void show_mid(BSTree* tree);

对应相关函数的实现：
创建二叉查找树：
Node* createNode(int data) &#123;
	Node* newNode &#x3D; (Node*)malloc(sizeof(Node));
	assert(newNode);
	newNode-&gt;key &#x3D; data;
	newNode-&gt;lchild &#x3D; NULL;
	newNode-&gt;rchild &#x3D; NULL;
	return newNode;
&#125;

向二叉查找树插入数据：
二叉查找树在插入数据的时候，都是把数据插入到树的叶子位置。
BSTree* insertNode(BSTree* tree, int data) &#123;
	if (tree &#x3D;&#x3D; NULL) return createNode(data);
	Node* pMove &#x3D; tree;
	Node* pBack &#x3D; NULL;
	while (pMove) &#123;
		pBack &#x3D; pMove;
		pMove &#x3D; data &lt; pMove-&gt;key ? pMove-&gt;lchild : pMove-&gt;rchild;
	&#125;
	if (data &lt; pBack-&gt;key)	 	pBack-&gt;lchild &#x3D; createNode(data);
	else 						pBack-&gt;rchild &#x3D; createNode(data);
	return tree;
&#125;

删除时需要的辅助函数：
&#x2F;&#x2F;找最大节点 最右边
Node* maxKeyNode(BSTree* tree) &#123;
	if (tree &#x3D;&#x3D; NULL) return NULL;
	while (tree-&gt;rchild)
		tree &#x3D; tree-&gt;rchild;
	return tree;
&#125;

在二叉查找树中删除节点：
首先先通过左右指针寻找，key和当前节点的key比较，小了就往左边走，大了就往右边走，等于的时候就停下来，删除它。
删除的时候，使用当前节点的左子树的最大值maxNode覆盖掉当前节点的key，然后再遍历到maxNode的位置将maxNode释放内存。这样做的好处是不需要大幅度改变原来树的结构，理解起来也比较简单。实现的时候采用递归的写法实现，这样比较简单，当然使用循环实现也是可以的，但是使用循环来实现比较麻烦。
Node* deleteNode(BSTree* tree, int key) &#123;
	if (tree &#x3D;&#x3D; NULL) return NULL;
	if (key &lt; tree-&gt;key)		tree-&gt;lchild &#x3D; deleteNode(tree-&gt;lchild, key);
	else if (key &gt; tree-&gt;key)	tree-&gt;rchild &#x3D; deleteNode(tree-&gt;rchild, key);
	else &#123;		&#x2F;&#x2F;tree对应要删除的节点
		if (tree-&gt;lchild !&#x3D; NULL &amp;&amp; tree-&gt;rchild !&#x3D; NULL) &#123;
			Node* max &#x3D; maxKeyNode(tree-&gt;lchild);
			tree-&gt;key &#x3D; max-&gt;key;
			tree-&gt;lchild &#x3D; deleteNode(tree-&gt;lchild, max-&gt;key);
		&#125;
		else &#123;
			Node* temp &#x3D; tree;
			tree &#x3D; tree-&gt;lchild ? tree-&gt;lchild : tree-&gt;rchild;
			free(temp);
		&#125;
	&#125;
	return tree;
&#125;

二叉查找的查找：
Node* searchNode(BSTree* tree, int key) &#123;
	Node* pMove &#x3D; tree;
	while (pMove &amp;&amp; pMove-&gt;key !&#x3D; key) &#123;
		if (key &lt; pMove-&gt;key)			pMove &#x3D; pMove-&gt;lchild;
		else if (key &gt; pMove-&gt;key)		pMove &#x3D; pMove-&gt;rchild;
		else 							break;
	&#125;
	return pMove;
&#125;

树的中序遍历：
void show_mid(BSTree* tree) &#123;
	if (tree &#x3D;&#x3D; NULL) return;
	show_mid(tree-&gt;lchild);
	printf(&quot;%d &quot;, tree-&gt;key);
	show_mid(tree-&gt;rchild);
&#125;

