            Constructor&lt;?&gt; constructor &#x3D; cs.getDeclaredConstructor();   &#x2F;&#x2F; 获得构造器（构造方法）
            Circle circle &#x3D; (Circle) constructor.newInstance();         &#x2F;&#x2F; 通过刚刚的构造器new一个实例
            circle.setRadius(100);
