    &#125;
    public int getMoney() &#123;
        return money;
    &#125;
&#125;


Main.java

public class Main &#123;
    public static void main(String[] args) &#123;
        Bank bank &#x3D; new Bank();
        try &#123;
            bank.income(200, -100);
            bank.income(300, -100);
            bank.income(400, -100);
            System.out.printf(&quot;银行目前有%d元\n&quot;,bank.getMoney());
            bank.income(200, 100);      &#x2F;&#x2F; 发生异常
            bank.income(99999, -100);   &#x2F;&#x2F; 没有被执行
        &#125;
        catch (BankException e) &#123;
