        public void speakHello() &#123;
                System.out.println(&quot;Hello&quot;);
        &#125;
&#125;
class KindHello &#123;
        public void lookHello(SpeakHello hello) &#123;
                hello.speakHello();
        &#125;
&#125;
public class Main &#123;
        public static void main(String[] args) &#123;
                KindHello k &#x3D; new KindHello();
                Chinese c &#x3D; new Chinese();
                k.lookHello(c);
